from django.db.models.sql.compiler import SQLCompiler


class ReturningSQLCompiler(SQLCompiler):
    def as_sql(self, *args, **kwargs):
        sql, params = super().as_sql(*args, **kwargs)
        if self.connection.features.can_return_id_from_insert and self.query.insert_id_is_required:
            sql = sql.rstrip() + ' RETURNING %s.%s' % (self.quote_name(self.query.model._meta.db_table), self.quote_name(self.query.model._meta.pk.column))
            params.append(self.query.model._meta.pk.name)
        return sql, params


class ReturningInsertCompiler(ReturningSQLCompiler):
    def as_sql(self, *args, **kwargs):
